const raw = $json.stdout || $json.data || $json.response || '';
const now = new Date().toISOString();
const lines = String(raw).split('\n').map(s => s.trim()).filter(Boolean);
const failureLines = lines.filter(l => /error|failed|failure|exit code|traceback|panic|exception|denied|ENOENT|EACCES/i.test(l)).slice(0, 20);
const files = lines.filter(l => l.startsWith('FILE_START ')).map(l => l.slice('FILE_START '.length));
const healthy = failureLines.length === 0;
const status = healthy ? 'No Failures Found' : 'Failures Detected';
const emoji = healthy ? '✅' : '🚨';
const first = failureLines[0] || 'No matching failures.';
const blocks = [ { type: 'header', text: { type: 'plain_text', text: `${emoji} OpenClaw Cron Failures` } }, { type: 'context', elements: [ { type: 'mrkdwn', text: `*Checked:* ${now}` }, { type: 'mrkdwn', text: `*Status:* ${status}` } ] }, { type: 'divider' }, { type: 'section', text: { type: 'mrkdwn', text: healthy ? 'No cron failures matched the scan.' : `*First Failure*\n\`\`\`\n${first}\n\`\`\`` } } ]; if (!healthy) blocks.push({ type: 'section', text: { type: 'mrkdwn', text: `*Other Failures*\n${failureLines.slice(1, 10).map(x => `• ${x}`).join('\n')}` } }); if (files.length) blocks.push({ type: 'context', elements: [ { type: 'mrkdwn', text: `*Scanned:* ${files.join(', ')}` } ] }); return [{ json: { checkedAt: now, status, healthy, failureLines, slackText: `${emoji} OpenClaw cron failures: ${status}`, slackBlocks: blocks } }];
